import * as vscode from 'vscode';
import { ImageFlowConfig, isGptImage2, isGptImage2Vip } from './shared';

const STORAGE_KEY = 'image-flow.config';
const DEFAULT_INJECTIONS: Record<string, string> = {
  'gpt-image-2': '整体画面弱化微小细节，避免过度刻画。',
  'gpt-image-2-vip': '整体画面弱化微小细节，避免过度刻画。',
};

/** 从 VS Code 配置读取所有配置项（不含 apiKey，apiKey 走 secrets） */
export function readConfig(): Omit<ImageFlowConfig, 'apiKey'> {
  const c = vscode.workspace.getConfiguration('image-flow');
  return {
    baseUrl: c.get<string>('baseUrl') ?? 'https://grsai.dakka.com.cn',
    model: c.get<string>('model') ?? 'nano-banana-2',
    aspectRatio: c.get<string>('aspectRatio') ?? '3:4',
    imageSize: c.get<string>('imageSize') ?? '1K',
    concurrency: c.get<number>('concurrency') ?? 1,
    workbenchCols: c.get<number>('workbenchCols') ?? 4,
    tasksCols: c.get<number>('tasksCols') ?? 2,
    modelInjections: c.get<Record<string, string>>('modelInjections') ?? {},
  };
}

/** 写入单个全局配置字段（合并语义，针对 modelInjections 执行深度合并） */
export async function writeConfigField(
  context: vscode.ExtensionContext,
  key: string,
  value: unknown
): Promise<void> {
  const config = vscode.workspace.getConfiguration('image-flow');
  await config.update(key, value, vscode.ConfigurationTarget.Global);
}

/** 获取 apiKey */
export async function getApiKey(context: vscode.ExtensionContext): Promise<string> {
  return (await context.secrets.get('image-flow.apiKey')) ?? '';
}

/** 设置 apiKey */
export async function setApiKey(context: vscode.ExtensionContext, key: string): Promise<void> {
  await context.secrets.store('image-flow.apiKey', key);
}

/** 种子模型注入提示词：补写配置中尚不存在的模型 key，用户改过（含清空为空串）不覆盖 */
export async function seedModelInjections(context: vscode.ExtensionContext): Promise<void> {
  const config = vscode.workspace.getConfiguration('image-flow');
  const current = config.get<Record<string, string>>('modelInjections') ?? {};
  let changed = false;
  for (const [model, injection] of Object.entries(DEFAULT_INJECTIONS)) {
    if (!(model in current)) {
      current[model] = injection;
      changed = true;
    }
  }
  if (changed) {
    await config.update('modelInjections', current, vscode.ConfigurationTarget.Global);
  }
}

/** 获取某个模型的注入句 */
export function getModelInjection(config: Omit<ImageFlowConfig, 'apiKey'>, model: string): string {
  return config.modelInjections[model] ?? '';
}

/** 获取素材库文件夹列表（workspaceState） */
export function getMaterialFolders(context: vscode.ExtensionContext): string[] {
  return context.workspaceState.get<string[]>('image-flow.materialFolders') ?? [];
}

/** 设置素材库文件夹列表 */
export async function setMaterialFolders(
  context: vscode.ExtensionContext,
  folders: string[]
): Promise<void> {
  await context.workspaceState.update('image-flow.materialFolders', folders);
}

import * as path from 'path';
import * as fs from 'fs';
import { mimeFromExt, isImageFile } from './shared';

/** 解析结果：替换后的文本 + 去重编号后的参考图 data URI 数组 */
export interface ParseResult {
  text: string;
  images: string[]; // data URI 数组
}

interface ImageRef {
  alt: string;
  imagePath: string; // 原始路径字符串（相对于 MD 所在目录的路径）
  startIndex: number;
  endIndex: number;
  angleBracket: boolean; // 是否 <> 包裹
}

/**
 * 解析 Markdown 中的图片引用，返回去重后的参考图引用列表（按首次出现顺序）。
 * 不在这里读取文件读取——交给调用者批量读。
 */
export function extractImageRefs(content: string): ImageRef[] {
  const refs: ImageRef[] = [];
  let pos = 0;

  while (pos < content.length) {
    const start = content.indexOf('![', pos);
    if (start === -1) break;

    const altEnd = content.indexOf(']', start + 2);
    if (altEnd === -1) break;
    if (content[altEnd + 1] !== '(') {
      pos = start + 2;
      continue;
    }

    const parenStart = altEnd + 1;
    const afterParen = parenStart + 1;

    if (content[afterParen] === '<') {
      // 尖括号包裹形式 ![alt](<path>)
      const pathEnd = content.indexOf('>)', afterParen + 1);
      if (pathEnd === -1) { pos = start + 2; continue; }
      const imagePath = content.slice(afterParen + 1, pathEnd);
      const alt = content.slice(start + 2, altEnd);
      refs.push({ alt, imagePath, startIndex: start, endIndex: pathEnd + 2, angleBracket: true });
      pos = pathEnd + 2;
    } else {
      // 普通形式 ![alt](path)
      const pathEnd = content.indexOf(')', parenStart + 1);
      if (pathEnd === -1) { pos = start + 2; continue; }
      const imagePath = content.slice(parenStart + 1, pathEnd);
      const alt = content.slice(start + 2, altEnd);
      refs.push({ alt, imagePath, startIndex: start, endIndex: pathEnd + 1, angleBracket: false });
      pos = pathEnd + 1;
    }
  }

  // 按路径去重，保留首次出现的序号
  const seen = new Map<string, number>();
  const deduped: (ImageRef & { num: number })[] = [];
  for (const ref of refs) {
    const existing = seen.get(ref.imagePath);
    if (existing !== undefined) {
      deduped.push({ ...ref, num: existing });
    } else {
      const num = seen.size + 1;
      seen.set(ref.imagePath, num);
      deduped.push({ ...ref, num });
    }
  }

  return deduped;
}

/**
 * 解析 Markdown 内容：替换图片语法为 [imageN](文件名去扩展名)，
 * 返回处理后的文本，调用者需自行读取参考图文件。
 * 返回每处引用对应的 num 与相对路径，方便调用者按 num 顺序组装 images 数组。
 */
export function parseMarkdown(content: string): {
  text: string;
  refs: Array<{ num: number; imagePath: string; alt: string }>;
} {
  const rawRefs = extractImageRefs(content);

  // 从后往前替换，避免索引偏移
  let text = content;
  for (let i = rawRefs.length - 1; i >= 0; i--) {
    const ref = rawRefs[i];
    const baseName = path.basename(ref.imagePath, path.extname(ref.imagePath));
    const replacement = `[image${ref.num}](${baseName})`;
    text = text.slice(0, ref.startIndex) + replacement + text.slice(ref.endIndex);
  }

  return {
    text,
    refs: rawRefs.map(r => ({ num: r.num, imagePath: r.imagePath, alt: r.alt })),
  };
}

/**
 * 读取参考图文件，转为 data URI。
 * 返回按编号顺序排列的 data URI 数组（去重：同一路径只读一次）。
 * 任何文件不可读即 throw。
 */
export function readRefImages(
  refs: Array<{ num: number; imagePath: string; alt: string }>,
  mdDir: string
): string[] {
  // 按 num 去重，取首次路径
  const byNum = new Map<number, string>();
  for (const ref of refs) {
    if (!byNum.has(ref.num)) {
      byNum.set(ref.num, ref.imagePath);
    }
  }

  const failed: string[] = [];
  const images: string[] = [];

  for (let num = 1; num <= byNum.size; num++) {
    const relPath = byNum.get(num);
    if (!relPath) {
      failed.push(`image${num}: 未找到路径`);
      continue;
    }
    const absPath = path.resolve(mdDir, relPath);
    try {
      const data = fs.readFileSync(absPath);
      const ext = path.extname(absPath).slice(1).toLowerCase();
      const mime = mimeFromExt(ext);
      const b64 = data.toString('base64');
      images.push(`data:${mime};base64,${b64}`);
    } catch {
      failed.push(absPath);
    }
  }

  if (failed.length > 0) {
    throw new Error(`参考图读取失败:\n${failed.join('\n')}`);
  }

  return images;
}

/** 完整处理 Markdown：解析 + 读取参考图 */
export function processMarkdown(content: string, mdDir: string): ParseResult {
  const { text, refs } = parseMarkdown(content);
  const images = refs.length > 0 ? readRefImages(refs, mdDir) : [];
  return { text, images };
}

import * as vscode from 'vscode';
import * as http from 'http';
import * as https from 'https';
import * as fs from 'fs';
import * as path from 'path';
import {
  ImageFlowConfig,
  isNanoBanana,
  isGptImage2Vip,
  calcVipPixels,
  VALID_STATUSES,
  extFromUrl,
} from './shared';

const TIMEOUT_MS = 30_000;

// ========== 运行时校验类型 ==========

interface ApiResult {
  id: string;
  status: string;
  results?: Array<{ url: string }>;
  progress?: number;
  error?: string;
}

function validateResult(data: unknown): ApiResult {
  if (!data || typeof data !== 'object') throw new Error('响应格式异常：非对象');
  const d = data as Record<string, unknown>;
  if (typeof d.id !== 'string') throw new Error('响应格式异常：缺少 id');
  if (typeof d.status !== 'string' || !VALID_STATUSES.has(d.status)) {
    throw new Error(`响应格式异常：无效 status "${d.status}"`);
  }
  if (d.results !== undefined) {
    if (!Array.isArray(d.results)) throw new Error('响应格式异常：results 非数组');
    for (const r of d.results) {
      if (!r || typeof r !== 'object' || typeof (r as Record<string, unknown>).url !== 'string') {
        throw new Error('响应格式异常：results[].url 缺失');
      }
    }
  }
  return {
    id: d.id as string,
    status: d.status as string,
    results: (d.results as Array<{ url: string }>) ?? [],
    progress: typeof d.progress === 'number' ? d.progress : undefined,
    error: typeof d.error === 'string' ? d.error : undefined,
  };
}

// ========== HTTP 工具 ==========

interface FetchResult {
  statusCode: number;
  data: unknown;
}

function fetchJson(url: string, options: https.RequestOptions, body?: string): Promise<FetchResult> {
  return new Promise((resolve, reject) => {
    const parsed = new URL(url);
    const lib = parsed.protocol === 'https:' ? https : http;
    const req = lib.request(
      parsed,
      {
        method: options.method ?? 'GET',
        headers: options.headers ?? {},
        timeout: TIMEOUT_MS,
      },
      (res) => {
        let raw = '';
        res.on('data', (chunk: Buffer) => { raw += chunk.toString(); });
        res.on('end', () => {
          try {
            const data = JSON.parse(raw);
            resolve({ statusCode: res.statusCode ?? 200, data });
          } catch {
            reject(new Error(`响应 JSON 解析失败: ${raw.slice(0, 200)}`));
          }
        });
      }
    );
    req.on('timeout', () => { req.destroy(); reject(new Error('请求超时')); });
    req.on('error', (e) => reject(e));
    if (body) req.write(body);
    req.end();
  });
}

// ========== 生成请求体构造 ==========

export interface GenerateParams {
  model: string;
  prompt: string;
  images: string[];
  config: Pick<ImageFlowConfig, 'aspectRatio' | 'imageSize' | 'baseUrl'>;
}

export function buildGenerateBody(params: GenerateParams): Record<string, unknown> {
  const body: Record<string, unknown> = {
    model: params.model,
    prompt: params.prompt,
    images: params.images,
    replyType: 'async',
  };

  if (isNanoBanana(params.model)) {
    body.aspectRatio = params.config.aspectRatio;
    body.imageSize = params.config.imageSize;
  } else if (isGptImage2Vip(params.model)) {
    body.aspectRatio = calcVipPixels(params.config.aspectRatio, params.config.imageSize);
  } else {
    // gpt-image-2
    body.aspectRatio = params.config.aspectRatio;
  }

  return body;
}

// ========== API 调用 ==========

/** 提交生成任务，返回 job id */
export async function submitGenerate(
  params: GenerateParams,
  apiKey: string
): Promise<string> {
  const body = buildGenerateBody(params);
  const url = `${params.config.baseUrl}/v1/api/generate`;

  const { statusCode, data } = await fetchJson(
    url,
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${apiKey}`,
      },
    },
    JSON.stringify(body)
  );

  if (statusCode >= 500 || statusCode === 429) {
    throw new Error(`服务器错误 (${statusCode})`);
  }

  const result = validateResult(data);

  if (result.status === 'failed' || result.status === 'violation') {
    throw new Error(result.error ?? '生成失败');
  }

  if (!result.id) {
    throw new Error('响应不含 id');
  }

  return result.id;
}

/** 查询生成结果 */
export async function queryResult(
  jobId: string,
  baseUrl: string,
  apiKey: string
): Promise<ApiResult> {
  const url = `${baseUrl}/v1/api/result?id=${encodeURIComponent(jobId)}`;
  const { statusCode, data } = await fetchJson(url, {
    method: 'GET',
    headers: { Authorization: `Bearer ${apiKey}` },
  });

  if (statusCode >= 500 || statusCode === 429) {
    throw new Error(`服务器错误 (${statusCode})`);
  }

  return validateResult(data);
}

/** 下载图片到本地 */
export function downloadImage(url: string, destPath: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const parsed = new URL(url);
    const lib = parsed.protocol === 'https:' ? https : http;
    const req = lib.get(parsed, { timeout: TIMEOUT_MS }, (res) => {
      if (res.statusCode && res.statusCode >= 400) {
        reject(new Error(`下载失败: HTTP ${res.statusCode}`));
        return;
      }
      const file = fs.createWriteStream(destPath);
      res.pipe(file);
      file.on('finish', () => { file.close(); resolve(); });
      file.on('error', (e) => reject(e));
    });
    req.on('timeout', () => { req.destroy(); reject(new Error('下载超时')); });
    req.on('error', (e) => reject(e));
  });
}

/** 判断错误是否瞬时（HTTP 5xx / 429 / fetch failed / abort） */
export function isTransientError(err: unknown): boolean {
  const msg = err instanceof Error ? err.message : String(err);
  return (
    msg.includes('服务器错误 (5') ||
    msg.includes('服务器错误 (429') ||
    msg.includes('请求超时') ||
    msg.includes('ECONNREFUSED') ||
    msg.includes('ENOTFOUND') ||
    msg.includes('EAI_AGAIN') ||
    msg.includes('fetch failed') ||
    msg.includes('abort') ||
    msg.includes('ETIMEDOUT')
  );
}

