import { useEffect, useRef, useCallback, useState } from 'react';

/** VS Code webview API 包装 */
export interface VSCodeApi {
  postMessage(msg: unknown): void;
  getState<T>(): T | undefined;
  setState<T>(state: T): void;
}

export function useVSCodeApi(): VSCodeApi {
  const ref = useRef<VSCodeApi | null>(null);
  if (!ref.current) {
    const vs = (window as unknown as { acquireVsCodeApi?: () => VSCodeApi }).acquireVsCodeApi?.();
    ref.current = vs ?? {
      postMessage: (msg: unknown) => {
        window.parent.postMessage(msg, '*');
      },
      getState: <T,>() => undefined as T | undefined,
      setState: <T,>(_s: T) => {},
    };
  }
  return ref.current;
}

/** 定时器 hook：interval ms 回调一次 */
export function useInterval(callback: () => void, delay: number | null): void {
  const savedCallback = useRef(callback);
  useEffect(() => {
    savedCallback.current = callback;
  }, [callback]);

  useEffect(() => {
    if (delay === null) return;
    const id = setInterval(() => savedCallback.current(), delay);
    return () => clearInterval(id);
  }, [delay]);
}

/** 格式化时长 mm:ss 或 h:mm:ss */
export function formatDuration(ms: number): string {
  if (ms <= 0) return '00:00';
  const totalSec = Math.floor(ms / 1000);
  const h = Math.floor(totalSec / 3600);
  const m = Math.floor((totalSec % 3600) / 60);
  const s = totalSec % 60;
  const pad = (n: number) => String(n).padStart(2, '0');
  if (h > 0) return `${h}:${pad(m)}:${pad(s)}`;
  return `${pad(m)}:${pad(s)}`;
}

/** 聚合进度：每个 job 占 1/N */
export function calcProgress(jobs: Array<{ status: string; progress: number }>): number {
  if (jobs.length === 0) return 0;
  let total = 0;
  for (const j of jobs) {
    if (j.status === 'succeeded') total += 1;
    else if (j.status === 'running') total += j.progress / 100;
    // submitting / failed → 0
  }
  return Math.round((total / jobs.length) * 100);
}

