import React from 'react';
import { AppCtx } from './App';
import { calcProgress } from './hooks';

export default function Workbench(): React.ReactElement {
  const { vscode, state, setState } = React.useContext(AppCtx);
  const {
    config,
    activeMdName,
    materials,
    autoMaterials,
    statusText,
    statusError,
  } = state;

  const [submitting, setSubmitting] = React.useState(false);

  const handleGenerate = () => {
    if (submitting) return;
    setSubmitting(true);
    vscode.postMessage({ type: 'generate' });
    // 提交后 5s 解禁
    setTimeout(() => setSubmitting(false), 5000);
  };

  const handlePreview = () => {
    vscode.postMessage({ type: 'preview' });
  };

  const handleInsertImage = (imagePath: string) => {
    vscode.postMessage({ type: 'insertImage', imagePath });
  };

  const handleOpenImage = (imagePath: string) => {
    vscode.postMessage({ type: 'openImage', imagePath });
  };

  const handleAddMaterial = () => {
    vscode.postMessage({ type: 'addMaterialFolder' });
  };

  const handleRemoveMaterial = (folderPath: string) => {
    vscode.postMessage({ type: 'removeMaterialFolder', path: folderPath });
  };

  // 图片点击打开原图
  const imgClick = (e: React.MouseEvent, p: string) => {
    e.preventDefault();
    handleOpenImage(p);
  };

  // 图片右键插入引用
  const imgContext = (e: React.MouseEvent, p: string) => {
    e.preventDefault();
    handleInsertImage(p);
  };

  const renderImageGrid = (images: string[], cols: number) => (
    <div className="image-grid" style={{ gridTemplateColumns: `repeat(${cols}, 1fr)` }}>
      {images.map((img, i) => (
        <div
          key={i}
          className="thumbnail"
          onClick={(e) => imgClick(e, img)}
          onContextMenu={(e) => imgContext(e, img)}
          title={img.split('/').pop() ?? img}
        >
          <img src={toWebviewUri(img)} alt="" loading="lazy" />
        </div>
      ))}
    </div>
  );

  return (
    <div className="workbench">
      {/* 素材库区 */}
      <div className="materials-section">
        {/* 自动素材库 */}
        {autoMaterials.length > 0 && (
          <div className="material-group">
            <div className="material-group-title">当前路径</div>
            {autoMaterials.map((m, i) => (
              <details key={i} className="material-folder">
                <summary>{m.name} ({m.images.length})</summary>
                {renderImageGrid(m.images, config.workbenchCols)}
              </details>
            ))}
          </div>
        )}

        {/* 手动素材库 */}
        <div className="material-group">
          <div className="material-group-title">
            手动素材库
            <button className="btn-small" onClick={handleAddMaterial}>+ 添加</button>
          </div>
          {materials.map((m, i) => (
            <details key={i} className="material-folder">
              <summary>
                {m.name} ({m.images.length})
                <button
                  className="btn-remove"
                  onClick={(e) => { e.preventDefault(); handleRemoveMaterial(m.path); }}
                >
                  ✕
                </button>
              </summary>
              {renderImageGrid(m.images, config.workbenchCols)}
            </details>
          ))}
        </div>
      </div>

      {/* 底部停靠区 */}
      <div className="workbench-dock">
        {/* 控件行 */}
        <div className="controls-row">
          <label>
            模型
            <select
              value={config.model}
              onChange={(e) => vscode.postMessage({ type: 'setConfig', key: 'model', value: e.target.value })}
            >
              <option value="nano-banana-2">nano-banana-2</option>
              <option value="nano-banana-pro">nano-banana-pro</option>
              <option value="gpt-image-2">gpt-image-2</option>
              <option value="gpt-image-2-vip">gpt-image-2-vip</option>
            </select>
          </label>
          <label>
            分辨率
            <select
              value={config.imageSize}
              onChange={(e) => vscode.postMessage({ type: 'setConfig', key: 'imageSize', value: e.target.value })}
            >
              <option value="1K">1K</option>
              <option value="2K">2K</option>
              <option value="4K">4K</option>
            </select>
          </label>
          <label>
            比例
            <select
              value={config.aspectRatio}
              onChange={(e) => vscode.postMessage({ type: 'setConfig', key: 'aspectRatio', value: e.target.value })}
            >
              <option value="1:1">1:1</option>
              <option value="16:9">16:9</option>
              <option value="9:16">9:16</option>
              <option value="4:3">4:3</option>
              <option value="3:4">3:4</option>
            </select>
          </label>
          <label>
            并发数
            <input
              type="number"
              min={1}
              max={10}
              value={config.concurrency}
              onChange={(e) => {
                const v = Math.max(1, Math.min(10, parseInt(e.target.value) || 1));
                vscode.postMessage({ type: 'setConfig', key: 'concurrency', value: v });
              }}
              className="stepper"
            />
          </label>
        </div>

        {/* 生成行 */}
        <div className="generate-row">
          <span className="active-md">
            {activeMdName || '未打开 Markdown 文件'}
          </span>
          <button className="btn" onClick={handlePreview}>预览请求</button>
          <button
            className="btn btn-primary"
            onClick={handleGenerate}
            disabled={submitting || !activeMdName}
          >
            {submitting ? '生成中…' : '生成'}
          </button>
        </div>

        {/* 状态行 */}
        {statusText && (
          <div className={`status-line ${statusError ? 'error' : ''}`}>
            {statusText}
          </div>
        )}
      </div>
    </div>
  );
}

/** 将文件绝对路径转为 webview 可用的 URI */
function toWebviewUri(absPath: string): string {
  // 在后端会用 asWebviewUri 转换，但前端也需要能显示
  // 对于已经通过 localResourceRoots 授权的路径，使用 vscode-resource: 协议
  // 实际上需要通过 postMessage 获取转换后的 URI
  // 简化为：直接用原始路径，后端会在发送前转换
  return absPath;
}

import React, { useState, useEffect } from 'react';
import { AppCtx } from './App';
import { useVSCodeApi, useInterval, formatDuration, calcProgress } from './hooks';
import { TaskState, JobState } from '../src/shared';

export default function Tasks(): React.ReactElement {
  const { vscode, state } = React.useContext(AppCtx);
  const { tasks, history, config } = state;
  const [now, setNow] = useState(Date.now());

  // 每秒自增计时
  useInterval(() => setNow(Date.now()), tasks.length > 0 ? 1000 : null);

  const handleOpenImage = (p: string) => {
    vscode.postMessage({ type: 'openImage', imagePath: p });
  };

  // 合并列表：进行中任务 + 历史，按文件夹名倒序
  const allItems: Array<
    { kind: 'running'; task: TaskState } | { kind: 'history'; folder: (typeof history)[0] }
  > = [];

  for (const task of tasks) {
    allItems.push({ kind: 'running', task });
  }
  for (const folder of history) {
    allItems.push({ kind: 'history', folder });
  }

  // 按文件夹名（含时间戳）倒序
  allItems.sort((a, b) => {
    const na = a.kind === 'running' ? a.task.folderName : a.folder.folderName;
    const nb = b.kind === 'running' ? b.task.folderName : b.folder.folderName;
    return nb.localeCompare(na);
  });

  if (allItems.length === 0) {
    return <div className="empty-state">暂无任务</div>;
  }

  return (
    <div className="tasks-page">
      {allItems.map((item, i) => {
        if (item.kind === 'running') {
          const task = item.task;
          const progress = calcProgress(task.jobs);
          const done = task.jobs.filter(j => j.status === 'succeeded').length;
          const total = task.jobs.length;
          const failed = task.jobs.filter(j => j.status === 'failed').length;
          const elapsed = now - task.startedAt;

          // 收集所有已下载图片
          const allImages: { jobIdx: number; img: string }[] = [];
          for (let ji = 0; ji < task.jobs.length; ji++) {
            for (const img of task.jobs[ji].downloadedImages) {
              allImages.push({ jobIdx: ji, img });
            }
          }

          // 任务文件夹绝对路径
          const mdDir = (task as TaskState & { mdPath: string }).mdPath
            ? require('path').dirname((task as TaskState & { mdPath: string }).mdPath)
            : '';
          // 实际上 mdPath 没有暴露给前端的 TaskState...
          // 不过我们可以从 folderName 和 activeMdPath 推断
          // 简化：使用 state.activeMdPath
          const taskDirBase = state.activeMdPath
            ? state.activeMdPath.replace(/[^/\\]*$/, '') + task.folderName + '/'
            : '';

          return (
            <details key={`running-${i}`} className="task-card running" open>
              <summary className="task-summary">
                <span className="task-title">
                  {task.folderName}（{task.model}）·
                  生成中 {done}/{total}
                  {failed > 0 && <> · 失败 {failed}</>}·
                  {formatDuration(elapsed)}
                </span>
              </summary>

              <div className="task-body">
                {/* 进度条 */}
                <div className="progress-bar">
                  <div
                    className="progress-fill"
                    style={{ width: `${progress}%` }}
                  />
                  <span className="progress-text">{progress}%</span>
                </div>

                {/* 缩略图 */}
                {allImages.length > 0 && (
                  <div
                    className="image-grid"
                    style={{ gridTemplateColumns: `repeat(${config.tasksCols}, 1fr)` }}
                  >
                    {allImages.map((img, ii) => (
                      <div
                        key={ii}
                        className="thumbnail"
                        onClick={() => handleOpenImage(taskDirBase + img.img)}
                        title={img.img}
                      >
                        <img
                          src={toWebviewUri(taskDirBase + img.img)}
                          alt=""
                          loading="lazy"
                        />
                      </div>
                    ))}
                  </div>
                )}

                {/* 提示信息 */}
                {task.jobs.some(j => j.status === 'submitting') && (
                  <div className="task-info">
                    正在提交 {task.jobs.filter(j => j.status === 'submitting').length} 个请求…
                  </div>
                )}
                {task.jobs.some(j => j.status === 'running') && (
                  <div className="task-info">
                    还有 {task.jobs.filter(j => j.status === 'running').length} 张正在生成…
                  </div>
                )}

                {/* 错误列表 */}
                {task.jobs.filter(j => j.error).map((j, ji) => (
                  <div key={ji} className="task-error">Job {ji + 1}: {j.error}</div>
                ))}
              </div>
            </details>
          );
        }

        // 历史卡片
        const folder = item.folder;
        const imgPaths = folder.images.map(f => folder.path + '/' + f);

        return (
          <details key={`hist-${i}`} className="task-card history">
            <summary className="task-summary">
              {folder.folderName}（{folder.images.length} 张）
            </summary>
            <div
              className="image-grid"
              style={{ gridTemplateColumns: `repeat(${config.tasksCols}, 1fr)` }}
            >
              {imgPaths.map((p, ii) => (
                <div
                  key={ii}
                  className="thumbnail"
                  onClick={() => handleOpenImage(p)}
                  title={folder.images[ii]}
                >
                  <img src={toWebviewUri(p)} alt="" loading="lazy" />
                </div>
              ))}
            </div>
          </details>
        );
      })}
    </div>
  );
}

function toWebviewUri(absPath: string): string {
  return absPath;
}

import React from 'react';
import { AppCtx } from './App';

const API_KEY_URL = 'https://grsai.ai/zh/dashboard/api-keys';

export default function Settings(): React.ReactElement {
  const { vscode, state } = React.useContext(AppCtx);
  const { config } = state;

  const [apiKeyInput, setApiKeyInput] = React.useState('');
  const [injectionModel, setInjectionModel] = React.useState(config.model);
  const [injectionText, setInjectionText] = React.useState('');

  // 同步注入文本当选中模型变化时
  React.useEffect(() => {
    setInjectionText(config.modelInjections[injectionModel] ?? '');
  }, [injectionModel, config.modelInjections]);

  const handleSaveApiKey = () => {
    vscode.postMessage({ type: 'setApiKey', value: apiKeyInput });
    setApiKeyInput('');
  };

  const handleSaveInjection = () => {
    vscode.postMessage({
      type: 'setModelInjection',
      model: injectionModel,
      injection: injectionText,
    });
  };

  const handleOpenApiKeyUrl = () => {
    vscode.postMessage({ type: 'openUrl', url: API_KEY_URL });
  };

  return (
    <div className="settings-page">
      {/* API Key */}
      <div className="setting-group">
        <label className="setting-label">
          API Key
          <a
            href="#"
            className="link-small"
            onClick={(e) => { e.preventDefault(); handleOpenApiKeyUrl(); }}
          >
            获取 API Key →
          </a>
        </label>
        <div className="setting-row">
          <input
            type="password"
            className="text-input"
            value={apiKeyInput}
            onChange={(e) => setApiKeyInput(e.target.value)}
            placeholder={config.apiKey ? '已设置 (••••••••)' : '请输入 API Key'}
          />
          <button className="btn btn-small" onClick={handleSaveApiKey}>
            保存
          </button>
        </div>
        {config.apiKey && (
          <div className="setting-hint success">API Key 已配置</div>
        )}
      </div>

      {/* 节点 */}
      <div className="setting-group">
        <label className="setting-label">节点</label>
        <select
          className="select-full"
          value={config.baseUrl}
          onChange={(e) =>
            vscode.postMessage({ type: 'setConfig', key: 'baseUrl', value: e.target.value })
          }
        >
          <option value="https://grsai.dakka.com.cn">国内节点 (grsai.dakka.com.cn)</option>
          <option value="https://grsaiapi.com">全球节点 (grsaiapi.com)</option>
        </select>
      </div>

      {/* 工作台每行张数 */}
      <div className="setting-group">
        <label className="setting-label">工作台素材缩略图每行张数</label>
        <input
          type="number"
          min={1}
          max={8}
          value={config.workbenchCols}
          onChange={(e) => {
            const v = Math.max(1, Math.min(8, parseInt(e.target.value) || 4));
            vscode.postMessage({ type: 'setConfig', key: 'workbenchCols', value: v });
          }}
          className="stepper"
        />
      </div>

      {/* 任务每行张数 */}
      <div className="setting-group">
        <label className="setting-label">任务页缩略图每行张数</label>
        <input
          type="number"
          min={1}
          max={8}
          value={config.tasksCols}
          onChange={(e) => {
            const v = Math.max(1, Math.min(8, parseInt(e.target.value) || 2));
            vscode.postMessage({ type: 'setConfig', key: 'tasksCols', value: v });
          }}
          className="stepper"
        />
      </div>

      {/* 模型注入提示词 */}
      <div className="setting-group">
        <label className="setting-label">模型注入提示词</label>
        <select
          className="select-full"
          value={injectionModel}
          onChange={(e) => setInjectionModel(e.target.value)}
        >
          <option value="nano-banana-2">nano-banana-2</option>
          <option value="nano-banana-pro">nano-banana-pro</option>
          <option value="gpt-image-2">gpt-image-2</option>
          <option value="gpt-image-2-vip">gpt-image-2-vip</option>
        </select>
        <textarea
          className="text-area"
          rows={3}
          value={injectionText}
          onChange={(e) => setInjectionText(e.target.value)}
          placeholder="输入该模型的注入提示词（留空表示不注入）"
        />
        <button className="btn btn-small" onClick={handleSaveInjection}>
          保存注入提示词
        </button>
      </div>
    </div>
  );
}

/* image-flow 侧栏样式 */

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --bg: var(--vscode-sideBar-background, #1e1e1e);
  --fg: var(--vscode-sideBar-foreground, #cccccc);
  --border: var(--vscode-sideBar-border, #333);
  --accent: var(--vscode-button-background, #0078d4);
  --accent-fg: var(--vscode-button-foreground, #fff);
  --input-bg: var(--vscode-input-background, #3c3c3c);
  --input-fg: var(--vscode-input-foreground, #ccc);
  --error: #f14c4c;
  --warn: #cca700;
  --radius: 4px;
  --gap: 8px;
}

html, body, #root {
  height: 100%;
  background: var(--bg);
  color: var(--fg);
  font-size: 13px;
  font-family: var(--vscode-font-family);
  line-height: 1.4;
  overflow: hidden;
}

.app {
  display: flex;
  flex-direction: column;
  height: 100%;
}

/* ========== Tab 栏 ========== */

.tab-bar {
  display: flex;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.tab-btn {
  flex: 1;
  padding: 6px 0;
  border: none;
  border-bottom: 2px solid transparent;
  background: transparent;
  color: var(--fg);
  cursor: pointer;
  font-size: 12px;
  transition: background 0.15s;
}

.tab-btn:hover {
  background: rgba(128, 128, 128, 0.1);
}

.tab-btn.active {
  border-bottom-color: var(--accent);
  color: var(--accent-fg, var(--accent));
}

/* ========== Tab 内容区 ========== */

.tab-content {
  flex: 1;
  overflow-y: auto;
  padding: var(--gap);
}

/* ========== 通用按钮 ========== */

.btn {
  padding: 4px 12px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--input-bg);
  color: var(--fg);
  cursor: pointer;
  font-size: 12px;
}

.btn:hover {
  background: rgba(128, 128, 128, 0.2);
}

.btn-primary {
  background: var(--accent);
  color: var(--accent-fg);
  border-color: var(--accent);
}

.btn-primary:hover {
  opacity: 0.9;
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.btn-small {
  padding: 2px 6px;
  font-size: 11px;
}

.btn-remove {
  background: none;
  border: none;
  color: var(--error);
  cursor: pointer;
  font-size: 14px;
  padding: 0 4px;
  float: right;
}

/* ========== 输入控件 ========== */

.text-input {
  width: 100%;
  padding: 4px 8px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--input-bg);
  color: var(--input-fg);
  font-size: 12px;
}

.stepper {
  width: 60px;
  padding: 2px 4px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--input-bg);
  color: var(--input-fg);
  font-size: 12px;
  text-align: center;
}

select {
  padding: 2px 4px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--input-bg);
  color: var(--input-fg);
  font-size: 12px;
}

.select-full {
  width: 100%;
  margin-bottom: 4px;
}

.text-area {
  width: 100%;
  padding: 4px 8px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--input-bg);
  color: var(--input-fg);
  font-size: 12px;
  resize: vertical;
  margin-bottom: 4px;
}

/* ========== 素材库 ========== */

.materials-section {
  margin-bottom: var(--gap);
}

.material-group {
  margin-bottom: var(--gap);
}

.material-group-title {
  font-weight: 600;
  margin-bottom: 4px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.material-folder {
  margin-left: 4px;
}

.material-folder summary {
  cursor: pointer;
  padding: 2px 0;
  font-size: 12px;
  color: var(--fg);
}

/* ========== 图片网格 ========== */

.image-grid {
  display: grid;
  gap: 4px;
  margin-top: 4px;
}

.thumbnail {
  aspect-ratio: 1;
  overflow: hidden;
  border-radius: var(--radius);
  border: 1px solid var(--border);
  cursor: pointer;
  background: #000;
}

.thumbnail img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.thumbnail:hover {
  border-color: var(--accent);
}

/* ========== 工作台停靠区 ========== */

.workbench-dock {
  border-top: 1px solid var(--border);
  padding-top: var(--gap);
  margin-top: auto;
}

.controls-row {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr 60px;
  gap: 4px;
  margin-bottom: var(--gap);
}

.controls-row label {
  font-size: 11px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.controls-row select,
.controls-row input {
  width: 100%;
}

.generate-row {
  display: flex;
  align-items: center;
  gap: var(--gap);
  margin-bottom: var(--gap);
}

.active-md {
  flex: 1;
  font-size: 11px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--fg);
  opacity: 0.7;
}

.status-line {
  font-size: 12px;
  padding: 4px 0;
}

.status-line.error {
  color: var(--error);
}

/* ========== 任务页 ========== */

.tasks-page {
  display: flex;
  flex-direction: column;
  gap: var(--gap);
}

.empty-state {
  text-align: center;
  padding: 24px;
  opacity: 0.5;
}

.task-card {
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: var(--gap);
}

.task-card.running {
  border-left: 3px solid var(--accent);
}

.task-card.history {
  border-left: 3px solid transparent;
}

.task-summary {
  cursor: pointer;
  font-size: 12px;
  font-weight: 500;
  list-style: none;
}

.task-summary::-webkit-details-marker {
  display: none;
}

.task-title {
  display: inline-block;
  max-width: 100%;
  overflow: hidden;
  text-overflow: ellipsis;
}

.task-body {
  margin-top: var(--gap);
}

/* 进度条 */
.progress-bar {
  height: 6px;
  background: var(--input-bg);
  border-radius: 3px;
  margin-bottom: var(--gap);
  position: relative;
}

.progress-fill {
  height: 100%;
  background: var(--accent);
  border-radius: 3px;
  transition: width 0.3s;
}

.progress-text {
  position: absolute;
  right: 4px;
  top: -4px;
  font-size: 10px;
}

.task-info {
  font-size: 11px;
  opacity: 0.7;
  margin-bottom: 4px;
}

.task-error {
  font-size: 11px;
  color: var(--error);
  margin-bottom: 2px;
  word-break: break-all;
}

/* ========== 设置页 ========== */

.settings-page {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.setting-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.setting-label {
  font-size: 12px;
  font-weight: 500;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.setting-row {
  display: flex;
  gap: 4px;
}

.setting-row .text-input {
  flex: 1;
}

.setting-hint {
  font-size: 11px;
}

.setting-hint.success {
  color: #4ec94e;
}

.link-small {
  font-size: 11px;
  color: var(--accent);
  text-decoration: none;
}

.link-small:hover {
  text-decoration: underline;
}

