import * as assert from 'assert';
import { extractImageRefs, parseMarkdown } from '../parser';

suite('图片语法解析与替换', () => {

  test('普通路径解析', () => {
    const md = 'hello ![cat](images/cat.png) world ![dog](dogs/dog.jpg) end';
    const refs = extractImageRefs(md);
    assert.strictEqual(refs.length, 2);
    assert.strictEqual(refs[0].imagePath, 'images/cat.png');
    assert.strictEqual(refs[0].num, 1);
    assert.strictEqual(refs[1].imagePath, 'dogs/dog.jpg');
    assert.strictEqual(refs[1].num, 2);
  });

  test('尖括号路径（含空格和括号）', () => {
    const md = '![img](<my images (1)/photo (copy).png>) text ![x](normal.png)';
    const refs = extractImageRefs(md);
    assert.strictEqual(refs.length, 2);
    assert.strictEqual(refs[0].imagePath, 'my images (1)/photo (copy).png');
    assert.strictEqual(refs[0].num, 1);
    assert.strictEqual(refs[1].imagePath, 'normal.png');
    assert.strictEqual(refs[1].num, 2);
  });

  test('重复引用复用编号', () => {
    const md = '![a](a.png) ![b](b.png) ![a2](a.png) ![c](c.png) ![b2](b.png)';
    const refs = extractImageRefs(md);
    assert.strictEqual(refs.length, 5);
    assert.strictEqual(refs[0].num, 1); // a.png → 1
    assert.strictEqual(refs[1].num, 2); // b.png → 2
    assert.strictEqual(refs[2].num, 1); // a.png → 复用 1
    assert.strictEqual(refs[3].num, 3); // c.png → 3
    assert.strictEqual(refs[4].num, 2); // b.png → 复用 2
  });

  test('替换文本：编号正确替换', () => {
    const md = 'start ![a](img/a.png) middle ![b](img/b.png) end';
    const result = parseMarkdown(md);
    assert.strictEqual(result.text, 'start [image1](a) middle [image2](b) end');
  });

  test('替换文本：重复引用保持编号', () => {
    const md = '![a](a.png) ![b](b.png) ![a2](a.png)';
    const result = parseMarkdown(md);
    assert.strictEqual(result.text, '[image1](a) [image2](b) [image1](a)');
  });

  test('无图片引用返回原文本', () => {
    const md = 'just some text **bold** no images';
    const result = parseMarkdown(md);
    assert.strictEqual(result.text, md);
    assert.strictEqual(result.refs.length, 0);
  });

  test('尖括号路径替换后保留正确引用', () => {
    const md = 'pre ![img](<path with spaces.png>) post';
    const result = parseMarkdown(md);
    assert.strictEqual(result.text, 'pre [image1](path with spaces) post');
    assert.strictEqual(result.refs[0].imagePath, 'path with spaces.png');
    assert.strictEqual(result.refs[0].num, 1);
  });
});

import * as assert from 'assert';
import { isTransientError } from '../api';
import { calcVipPixels } from '../shared';

suite('瞬时错误判定', () => {

  test('HTTP 5xx 为瞬时错误', () => {
    assert.strictEqual(isTransientError(new Error('服务器错误 (500)')), true);
    assert.strictEqual(isTransientError(new Error('服务器错误 (502)')), true);
    assert.strictEqual(isTransientError(new Error('服务器错误 (503)')), true);
  });

  test('HTTP 429 为瞬时错误', () => {
    assert.strictEqual(isTransientError(new Error('服务器错误 (429)')), true);
  });

  test('fetch failed 为瞬时错误', () => {
    assert.strictEqual(isTransientError(new Error('fetch failed')), true);
  });

  test('abort/超时为瞬时错误', () => {
    assert.strictEqual(isTransientError(new Error('请求超时')), true);
    assert.strictEqual(isTransientError(new Error('abort')), true);
  });

  test('ECONNREFUSED 为瞬时错误', () => {
    assert.strictEqual(isTransientError(new Error('ECONNREFUSED')), true);
    assert.strictEqual(isTransientError(new Error('ETIMEDOUT')), true);
  });

  test('格式错误非瞬时', () => {
    assert.strictEqual(isTransientError(new Error('响应格式异常：缺少 id')), false);
    assert.strictEqual(isTransientError(new Error('响应 JSON 解析失败')), false);
    assert.strictEqual(isTransientError(new Error('something else')), false);
  });
});

suite('gpt-image-2-vip 像素换算', () => {

  test('1:1 + 1K', () => {
    const result = calcVipPixels('1:1', '1K');
    const [w, h] = result.split('x').map(Number);
    assert.strictEqual(w, 1008);
    assert.strictEqual(h, 1008);
    assert.ok(w % 16 === 0 && h % 16 === 0);
  });

  test('3:4 + 1K → 864x1152', () => {
    const result = calcVipPixels('3:4', '1K');
    assert.strictEqual(result, '864x1152');
  });

  test('4:3 + 1K', () => {
    const result = calcVipPixels('4:3', '1K');
    const [w, h] = result.split('x').map(Number);
    assert.ok(Math.abs(w / h - 4 / 3) < 0.02);
    assert.ok(w % 16 === 0 && h % 16 === 0);
  });

  test('16:9 + 2K', () => {
    const result = calcVipPixels('16:9', '2K');
    const [w, h] = result.split('x').map(Number);
    assert.ok(Math.abs(w / h - 16 / 9) < 0.02);
    assert.ok(w % 16 === 0 && h % 16 === 0);
    // 2K ~4MP
    assert.ok(w * h >= 3_800_000 && w * h <= 4_200_000);
  });

  test('9:16 + 4K', () => {
    const result = calcVipPixels('9:16', '4K');
    const [w, h] = result.split('x').map(Number);
    assert.ok(Math.abs(w / h - 9 / 16) < 0.02);
    assert.ok(w % 16 === 0 && h % 16 === 0);
    // 4K ~16MP, max side 3840
    assert.ok(w <= 3840 && h <= 3840);
  });

  test('所有结果均为 16 的倍数', () => {
    const ratios = ['1:1', '16:9', '9:16', '4:3', '3:4'];
    const sizes = ['1K', '2K', '4K'];
    for (const r of ratios) {
      for (const s of sizes) {
        const result = calcVipPixels(r, s);
        const [w, h] = result.split('x').map(Number);
        assert.ok(w % 16 === 0, `${r} ${s}: width ${w} not multiple of 16`);
        assert.ok(h % 16 === 0, `${r} ${s}: height ${h} not multiple of 16`);
      }
    }
  });
});

import * as assert from 'assert';
import { calcProgress, formatDuration } from '../../webview/hooks';

suite('聚合进度计算', () => {

  test('全 submitting 态 → 0%', () => {
    const jobs = [
      { status: 'submitting', progress: 0 },
      { status: 'submitting', progress: 0 },
    ];
    assert.strictEqual(calcProgress(jobs), 0);
  });

  test('混合态：1 running 50% + 1 succeeded → 75%', () => {
    const jobs = [
      { status: 'running', progress: 50 },
      { status: 'succeeded', progress: 100 },
    ];
    assert.strictEqual(calcProgress(jobs), 75);
  });

  test('混合态：1 running 0% + 1 succeeded + 1 submitting → 33%', () => {
    const jobs = [
      { status: 'running', progress: 0 },
      { status: 'succeeded', progress: 100 },
      { status: 'submitting', progress: 0 },
    ];
    assert.strictEqual(calcProgress(jobs), 33);
  });

  test('全部终结 → 100%', () => {
    const jobs = [
      { status: 'succeeded', progress: 100 },
      { status: 'succeeded', progress: 100 },
      { status: 'succeeded', progress: 100 },
    ];
    assert.strictEqual(calcProgress(jobs), 100);
  });

  test('含 failed 的混合态', () => {
    const jobs = [
      { status: 'succeeded', progress: 100 },
      { status: 'failed', progress: 0 },
      { status: 'running', progress: 50 },
    ];
    assert.strictEqual(calcProgress(jobs), 50);
  });

  test('单个 running 50% → 50%', () => {
    const jobs = [
      { status: 'running', progress: 50 },
    ];
    assert.strictEqual(calcProgress(jobs), 50);
  });

  test('空数组 → 0%', () => {
    assert.strictEqual(calcProgress([]), 0);
  });
});

suite('formatDuration', () => {
  test('小于 1 分钟', () => {
    assert.strictEqual(formatDuration(30000), '00:30');
    assert.strictEqual(formatDuration(5000), '00:05');
  });

  test('1 分钟以上', () => {
    assert.strictEqual(formatDuration(65000), '01:05');
    assert.strictEqual(formatDuration(125000), '02:05');
  });

  test('1 小时以上', () => {
    assert.strictEqual(formatDuration(3600000), '1:00:00');
    assert.strictEqual(formatDuration(3665000), '1:01:05');
  });

  test('零/负数 → 00:00', () => {
    assert.strictEqual(formatDuration(0), '00:00');
    assert.strictEqual(formatDuration(-1000), '00:00');
  });
});

import * as assert from 'assert';
import { buildGenerateBody } from '../api';

suite('预览文本组装', () => {

  test('请求体剔除 prompt 和 images', () => {
    const body = buildGenerateBody({
      model: 'nano-banana-2',
      prompt: 'test prompt',
      images: ['data:image/png;base64,abc123'],
      config: {
        baseUrl: 'https://grsai.dakka.com.cn',
        aspectRatio: '1:1',
        imageSize: '1K',
      },
    });

    // 构建 JSON 后剔除 prompt 和 images
    const { prompt: _p, images: _i, ...rest } = body as Record<string, unknown> & { prompt: string; images: string[] };
    const json = JSON.stringify(rest, null, 2);

    assert.ok(!json.includes('"prompt"'));
    assert.ok(!json.includes('"images"'));
    assert.ok(!json.includes('test prompt'));
    assert.ok(!json.includes('data:image'));
    assert.ok(json.includes('"model"'));
    assert.ok(json.includes('nano-banana-2'));
    assert.ok(json.includes('"aspectRatio"'));
    assert.ok(json.includes('1:1'));
  });

  test('nano-banana 系列包含 aspectRatio 和 imageSize', () => {
    const body = buildGenerateBody({
      model: 'nano-banana-2',
      prompt: 'test',
      images: [],
      config: { baseUrl: '', aspectRatio: '4:3', imageSize: '2K' },
    });
    assert.strictEqual(body.aspectRatio, '4:3');
    assert.strictEqual(body.imageSize, '2K');
  });

  test('gpt-image-2 不包含 imageSize', () => {
    const body = buildGenerateBody({
      model: 'gpt-image-2',
      prompt: 'test',
      images: [],
      config: { baseUrl: '', aspectRatio: '16:9', imageSize: '2K' },
    });
    assert.strictEqual(body.aspectRatio, '16:9');
    assert.strictEqual('imageSize' in body, false);
  });

  test('gpt-image-2-vip 使用像素值', () => {
    const body = buildGenerateBody({
      model: 'gpt-image-2-vip',
      prompt: 'test',
      images: [],
      config: { baseUrl: '', aspectRatio: '3:4', imageSize: '1K' },
    });
    assert.strictEqual(body.aspectRatio, '864x1152');
    assert.strictEqual('imageSize' in body, false);
  });

  test('replyType 始终为 async', () => {
    for (const model of ['nano-banana-2', 'gpt-image-2', 'gpt-image-2-vip']) {
      const body = buildGenerateBody({
        model,
        prompt: 'test',
        images: [],
        config: { baseUrl: '', aspectRatio: '1:1', imageSize: '1K' },
      });
      assert.strictEqual(body.replyType, 'async');
    }
  });

  test('参考图概览格式', () => {
    const images = ['data:image/png;base64,abcdefghijklmnopqrstuvwxyz0123456789ABCDEFGH'];
    // 预览截取前 48 字符
    const previews = images.map((img, i) => {
      const preview = img.slice(0, 48);
      return `image${i + 1}: ${preview}…（总长度 ${img.length}）`;
    });
    assert.strictEqual(previews.length, 1);
    assert.ok(previews[0].startsWith('image1: data:image/png;base64,abcdefghijklmnopqrstuvwxy'));
    assert.ok(previews[0].endsWith(`（总长度 ${images[0].length}）`));
  });

  test('无参考图注明', () => {
    const images: string[] = [];
    const refOverview = images.length === 0 ? '无参考图' : '有图';
    assert.strictEqual(refOverview, '无参考图');
  });
});

